\caption{MACAL\label{appendixalg:macal}}  egin{algorithmic}[1] \State Input: Initializing the training set $\mathcal{D}_{	ext{train}}=\mathcal{D}^{t=1}_{	ext{train}}\cup\mathcal{D}^{t=0}_{	ext{train}}$, pool set $\mathcal{D}_{	ext{pool}}=\mathcal{D}^{t=1}_{	ext{pool}}\cup\mathcal{D}^{t=0}_{	ext{pool}}$, batch size $S$, initial query step $Q=1$, symmetrical penalization $\alpha$, and maximum query step $Q_{	ext{max}}$. \For{$Q<Q_{	ext{max}}$} \State $\Tilde{\mathcal{D}}=\varnothing$ \While{$|\Tilde{\mathcal{D}}|<S$} \(	riangleright\) 	extcolor{gray}{Keep acquiring the samples if the batch is not filled up in each query step} \If{$\mathcal{D}^{t=1}_{	ext{pool}}
eq\varnothing and \mathcal{D}^{t=0}_{	ext{pool}}
eq\varnothing$} \(	riangleright\) 	extcolor{gray}{If both treatment groups still have available unlabelled samples} \State $\Tilde{x}^{t=1},\Tilde{x}^{t=0} \leftarrow\argmax_{(\Tilde{x}^{t=1},\Tilde{x}^{t=0})} \Sigma_{t\in\{0,1\}}	ext{min}_{x'\in\mathcal{D}^{t}_{	ext{train}}}d(\Tilde{x}^{t}, x')-\alpha d(\Tilde{x}^{t=1},\Tilde{x}^{t=0})$ \(	riangleright\) 	extcolor{gray}{Acquire the sample pairs} \State $\mathcal{D}^{t=1}_{	ext{train}}, \mathcal{D}^{t=0}_{	ext{train}}\leftarrow\mathcal{D}^{t=1}_{	ext{train}}\cup\{\Tilde{x}^{t=1}\}, \mathcal{D}^{t=0}_{	ext{train}}\cup\{\Tilde{x}^{t=0}\}$ \(	riangleright\) 	extcolor{gray}{Add the unlabelled samples into the training sets} \Statex $\mathcal{D}^{t=1}_{	ext{pool}},\mathcal{D}^{t=0}_{	ext{pool}}\leftarrow\mathcal{D}^{t=1}_{	ext{pool}} ackslash\{\Tilde{x}^{t=1}\}, \mathcal{D}^{t=0}_{	ext{pool}} ackslash\{\Tilde{x}^{t=0}\}$ \(	riangleright\) 	extcolor{gray}{Exclude the acquired samples from the pool sets} \Statex $\Tilde{\mathcal{D}}\leftarrow\Tilde{\mathcal{D}}\cup\{\Tilde{x}^{t=1},\Tilde{x}^{t=0}\}$ \(	riangleright\) 	extcolor{gray}{Update the acquired batch} \Else{} \(	riangleright\) 	extcolor{gray}{If one of the treatment groups' pool set is exhausted} \If{$\mathcal{D}^{t=1}_{	ext{pool}}
eq\varnothing$} \(	riangleright\) 	extcolor{gray}{If treatment group with $t=1$ is not exhausted} \State $\Tilde{x}^{t=1} \leftarrow\argmax_{\Tilde{x}^{t=1}\in\mathcal{D}^{t=1}} 	ext{min}_{x'\in\mathcal{D}^{t=1}_{	ext{train}}}d(\Tilde{x}^{t}, x')$ \State $\mathcal{D}^{t=1}_{	ext{train}}, \mathcal{D}^{t=1}_{	ext{pool}}, \Tilde{\mathcal{D}}\leftarrow\mathcal{D}^{t=1}_{	ext{train}}\cup\{\Tilde{x}^{t=1}\}, \mathcal{D}^{t=1}_{	ext{pool}} ackslash\{\Tilde{x}^{t=1}\},\Tilde{\mathcal{D}}\cup\{\Tilde{x}^{t=1}\}$ \Else{} \(	riangleright\) 	extcolor{gray}{If treatment group with $t=0$ is not exhausted} \State $\Tilde{x}^{t=0} \leftarrow\argmax_{\Tilde{x}^{t=0}\in\mathcal{D}^{t=0}} 	ext{min}_{x'\in\mathcal{D}^{t=0}_{	ext{train}}}d(\Tilde{x}^{t}, x')$ \State $\mathcal{D}^{t=0}_{	ext{train}}, \mathcal{D}^{t=0}_{	ext{pool}}, \Tilde{\mathcal{D}}\leftarrow\mathcal{D}^{t=1}_{	ext{train}}\cup\{\Tilde{x}^{t=0}\}, \mathcal{D}^{t=0}_{	ext{pool}} ackslash\{\Tilde{x}^{t=0}\},\Tilde{\mathcal{D}}\cup\{\Tilde{x}^{t=0}\}$ \EndIf \EndIf \EndWhile \State Reveal the acquired unlabelled samples in the training set via the Oracle. \(	riangleright\) 	extcolor{gray}{Label all the acquired samples all at once} \State $Q\leftarrow Q+1$ \(	riangleright\) 	extcolor{gray}{Move to next query step} \EndFor \State Output: $\mathcal{D}_{	ext{train}}$. \end{algorithmic}
